func RegSetValueEx(hKey systemregistry.HKEY, lpValueName string, dwType systemregistry.REG_VALUE_TYPE, lpData *byte, cbData uint32) foundation.WIN32_ERROR {
	_lpValueName := win32.UTF16Ptr(lpValueName)
	return systemregistry.RegSetValueExW(hKey, foundation.PWSTR(_lpValueName), 0, dwType, lpData, cbData)
}

// RegSetValueExA wraps the raw RegSetValueExA call with idiomatic Go types.
// https://learn.microsoft.com/windows/win32/api/winreg/nf-winreg-regsetvalueexa
func RegSetValueExA(hKey systemregistry.HKEY, lpValueName foundation.PSTR, dwType systemregistry.REG_VALUE_TYPE, lpData *byte, cbData uint32) foundation.WIN32_ERROR {
	return systemregistry.RegSetValueExA(hKey, lpValueName, 0, dwType, lpData, cbData)
}

// RegUnLoadKey wraps the raw RegUnLoadKeyW call with idiomatic Go types.
// https://learn.microsoft.com/windows/win32/api/winreg/nf-winreg-regunloadkeyw
func RegUnLoadKey(hKey systemregistry.HKEY, lpSubKey string) foundation.WIN32_ERROR {
	_lpSubKey := win32.UTF16Ptr(lpSubKey)
	return systemregistry.RegUnLoadKeyW(hKey, foundation.PWSTR(_lpSubKey))
}
